"use client";

import { useState } from "react";
import Image from "next/image";

type LeadQuality = "hot" | "warm" | "cold";

interface LeadResult {
  lead_quality: LeadQuality;
  summary: string;
  suggested_response: string;
}

const qualityConfig: Record<
  LeadQuality,
  { label: string; bg: string; text: string; dot: string; border: string; glow: string }
> = {
  hot: {
    label: "Hot Lead",
    bg: "bg-red-950/60",
    text: "text-red-300",
    dot: "bg-red-400",
    border: "border-red-700/50",
    glow: "shadow-red-900/40",
  },
  warm: {
    label: "Warm Lead",
    bg: "bg-amber-950/60",
    text: "text-amber-300",
    dot: "bg-amber-400",
    border: "border-amber-700/50",
    glow: "shadow-amber-900/40",
  },
  cold: {
    label: "Cold Lead",
    bg: "bg-blue-950/60",
    text: "text-blue-300",
    dot: "bg-blue-400",
    border: "border-blue-700/50",
    glow: "shadow-blue-900/40",
  },
};

const SERVICES = ["Plumbing", "HVAC", "Electricity"] as const;

export default function Home() {
  const [name, setName] = useState("");
  const [service, setService] = useState("");
  const [message, setMessage] = useState("");
  const [result, setResult] = useState<LeadResult | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    setResult(null);

    try {
      const res = await fetch("http://localhost:8000/analyze-lead", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name,
          service_needed: service,
          message,
        }),
      });

      if (!res.ok) {
        const data = await res.json().catch(() => ({}));
        throw new Error(data.detail ?? `Server error (${res.status})`);
      }

      const data: LeadResult = await res.json();
      setResult(data);
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Something went wrong.");
    } finally {
      setLoading(false);
    }
  };

  const q = result ? qualityConfig[result.lead_quality] : null;

  return (
    <main className="min-h-screen flex flex-col items-center justify-start py-14 px-4">
      <div className="w-full max-w-xl">

        {/* Hero header */}
        <div className="mb-10 text-center">
          {/* Logo mark */}
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl mb-5"
            style={{ background: "linear-gradient(135deg, #f59e0b, #ea580c)" }}>
            <svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M11.42 15.17L17.25 21A2.652 2.652 0 0021 17.25l-5.877-5.877M11.42 15.17l2.496-3.03c.317-.384.74-.626 1.208-.766M11.42 15.17l-4.655 5.653a2.548 2.548 0 11-3.586-3.586l6.837-5.63m5.108-.233c.55-.164 1.163-.188 1.743-.14a4.5 4.5 0 004.486-6.336l-3.276 3.277a3.004 3.004 0 01-2.25-2.25l3.276-3.276a4.5 4.5 0 00-6.336 4.486c.091 1.076-.071 2.264-.904 2.95l-.102.085m-1.745 1.437L5.909 7.5H4.5L2.25 3.75l1.5-1.5L7.5 4.5v1.409l4.26 4.26m-1.745 1.437l1.745-1.437m6.615 8.206L15.75 15.75M4.867 19.125h.008v.008h-.008v-.008z" />
            </svg>
          </div>

          <h1 className="text-4xl font-extrabold tracking-tight text-white">
            Mike&apos;s Every Task
          </h1>
          <p className="mt-2 text-base font-medium" style={{ color: "#f59e0b" }}>
            Plumbing · HVAC · Electricity
          </p>
        </div>

        {/* Divider */}
        <div className="flex items-center gap-3 mb-8">
          <div className="flex-1 h-px bg-slate-700/60" />
          <span className="text-xs font-semibold uppercase tracking-widest text-slate-500">Request a Service</span>
          <div className="flex-1 h-px bg-slate-700/60" />
        </div>

        {/* Form */}
        <form
          onSubmit={handleSubmit}
          className="rounded-2xl border border-slate-700/60 p-8 space-y-5 backdrop-blur-sm"
          style={{ background: "rgba(15,23,42,0.7)" }}
        >
          <div>
            <label className="block text-sm font-semibold text-slate-300 mb-1.5">
              Your Name
            </label>
            <input
              type="text"
              required
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="e.g. Jane Doe"
              className="w-full rounded-lg border border-slate-600/60 bg-slate-800/70 px-4 py-2.5 text-sm text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:border-transparent transition"
              style={{ "--tw-ring-color": "#f59e0b" } as React.CSSProperties}
              onFocus={(e) => (e.target.style.boxShadow = "0 0 0 2px #f59e0b")}
              onBlur={(e) => (e.target.style.boxShadow = "")}
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-300 mb-1.5">
              Service Needed
            </label>
            <select
              required
              value={service}
              onChange={(e) => setService(e.target.value)}
              className="w-full rounded-lg border border-slate-600/60 bg-slate-800/70 px-4 py-2.5 text-sm text-white focus:outline-none transition appearance-none cursor-pointer"
              style={{ backgroundImage: "url(\"data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 20 20'%3e%3cpath stroke='%236b7280' stroke-linecap='round' stroke-linejoin='round' stroke-width='1.5' d='M6 8l4 4 4-4'/%3e%3c/svg%3e\")", backgroundRepeat: "no-repeat", backgroundPosition: "right 0.75rem center", backgroundSize: "1.25em 1.25em", paddingRight: "2.5rem" }}
              onFocus={(e) => (e.target.style.boxShadow = "0 0 0 2px #f59e0b")}
              onBlur={(e) => (e.target.style.boxShadow = "")}
            >
              <option value="" disabled style={{ color: "#6b7280" }}>Select a service...</option>
              {SERVICES.map((s) => (
                <option key={s} value={s} style={{ background: "#1e293b", color: "#fff" }}>
                  {s}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-semibold text-slate-300 mb-1.5">
              Message
            </label>
            <textarea
              required
              rows={4}
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder="Describe your situation or what you need help with..."
              className="w-full rounded-lg border border-slate-600/60 bg-slate-800/70 px-4 py-2.5 text-sm text-white placeholder-slate-500 focus:outline-none transition resize-none"
              onFocus={(e) => (e.target.style.boxShadow = "0 0 0 2px #f59e0b")}
              onBlur={(e) => (e.target.style.boxShadow = "")}
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            className="w-full rounded-lg py-3 text-sm font-bold text-white transition disabled:opacity-50 disabled:cursor-not-allowed"
            style={{ background: loading ? "#92400e" : "linear-gradient(135deg, #f59e0b, #ea580c)" }}
          >
            {loading ? (
              <span className="flex items-center justify-center gap-2">
                <svg className="animate-spin h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                  <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                  <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z" />
                </svg>
                Analyzing your request...
              </span>
            ) : (
              "Submit Request"
            )}
          </button>
        </form>

        {/* Error */}
        {error && (
          <div className="mt-4 rounded-lg border border-red-700/50 bg-red-950/50 px-4 py-3 text-sm text-red-300">
            {error}
          </div>
        )}

        {/* Result */}
        {result && q && (
          <div
            className={`mt-6 rounded-2xl border p-8 space-y-6 ${q.border} backdrop-blur-sm`}
            style={{ background: "rgba(15,23,42,0.75)" }}
          >
            {/* Lead Quality Badge */}
            <div className="flex items-center gap-3">
              <span
                className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-bold border ${q.bg} ${q.text} ${q.border}`}
              >
                <span className={`w-2 h-2 rounded-full ${q.dot}`} />
                {q.label}
              </span>
              <span className="text-xs text-slate-500">AI Classification</span>
            </div>

            {/* Summary */}
            <div>
              <h3 className="text-xs font-bold uppercase tracking-widest mb-2" style={{ color: "#f59e0b" }}>
                Intent Summary
              </h3>
              <p className="text-sm text-slate-300 leading-relaxed">
                {result.summary}
              </p>
            </div>

            {/* Suggested Response */}
            <div>
              <h3 className="text-xs font-bold uppercase tracking-widest mb-2" style={{ color: "#f59e0b" }}>
                Suggested Response
              </h3>
              <div className="rounded-lg px-4 py-3 border border-slate-700/50 bg-slate-800/50">
                <p className="text-sm text-slate-300 leading-relaxed italic">
                  &ldquo;{result.suggested_response}&rdquo;
                </p>
              </div>
            </div>

            {/* Raw JSON toggle */}
            <details className="group">
              <summary className="cursor-pointer text-xs text-slate-500 hover:text-slate-400 select-none">
                View raw JSON
              </summary>
              <pre className="mt-3 text-xs bg-slate-900/70 border border-slate-700/50 rounded-lg p-4 overflow-auto text-slate-400">
                {JSON.stringify(result, null, 2)}
              </pre>
            </details>
          </div>
        )}

        {/* Footer */}
        <p className="mt-10 text-center text-xs text-slate-600">
          &copy; {new Date().getFullYear()} Mike&apos;s Every Task. All rights reserved.
        </p>
      </div>
    </main>
  );
}
